out vec4 fragColor;
float hash(vec2 p){ return fract(sin(dot(p, vec2(127.1, 311.7))) * 43758.5453); }
float vnoise(vec2 p){
    vec2 i = floor(p); vec2 f = fract(p);
    f = f*f*(3.0-2.0*f);
    float a = hash(i);
    float b = hash(i+vec2(1.0,0.0));
    float c = hash(i+vec2(0.0,1.0));
    float d = hash(i+vec2(1.0,1.0));
    return mix(mix(a,b,f.x), mix(c,d,f.x), f.y);
}
void main(){
    vec2 uv = vUV.st;
    float n = vnoise(uv * 14.0);
    float b = smoothstep(0.62, 0.70, n);
    fragColor = TDOutputSwizzle(vec4(1.0, b, 0.0, 1.0));
}

glsl_code.glsl1:
out vec4 fragColor;

uniform float uFeed;
uniform float uKill;

vec2 sampleAB(vec2 uv) { return texture(sTD2DInputs[0], uv).rg; }

void main()
{
    vec2 uv = vUV.st;
    vec2 texel = uTD2DInfos[0].res.xy;
    vec2 c = sampleAB(uv);
    float a = c.r;
    float b = c.g;

    vec2 lap = vec2(0.0);
    lap += sampleAB(uv + texel * vec2(-1.0, 0.0)) * 0.2;
    lap += sampleAB(uv + texel * vec2( 1.0, 0.0)) * 0.2;
    lap += sampleAB(uv + texel * vec2( 0.0,-1.0)) * 0.2;
    lap += sampleAB(uv + texel * vec2( 0.0, 1.0)) * 0.2;
    lap += sampleAB(uv + texel * vec2(-1.0,-1.0)) * 0.05;
    lap += sampleAB(uv + texel * vec2( 1.0,-1.0)) * 0.05;
    lap += sampleAB(uv + texel * vec2(-1.0, 1.0)) * 0.05;
    lap += sampleAB(uv + texel * vec2( 1.0, 1.0)) * 0.05;
    lap -= c;

    float reaction = a * b * b;
    float da = 1.0 * lap.r - reaction + uFeed * (1.0 - a);
    float db = 0.5 * lap.g + reaction - (uKill + uFeed) * b;

    float a2 = clamp(a + da, 0.0, 1.0);
    float b2 = clamp(b + db, 0.0, 1.0);
    fragColor = TDOutputSwizzle(vec4(a2, b2, 0.0, 1.0));
}
